const (
	defaultWorkerDirStaleAge          = 30 * time.Minute
	executionRetentionArchiveRoot     = ".ddx/executions-archive"
	executionRetentionOverrideEnv     = "DDX_EXECUTION_RETAIN_DAYS"
	executionRetentionTimestampLayout = "20060102T150405"
)

type executionRetentionMode int

const (
	executionRetentionDisabled executionRetentionMode = iota
	executionRetentionArchive
	executionRetentionDelete
)

type executionRetentionPolicy struct {
	days int
	mode executionRetentionMode
}

type startupHousekeepingReport struct {
	ProjectRoot string
	TempRoot    string

	StaleWorktrees     int64
	StaleWorkerDirs    int64
	StaleExecutionDirs int64

	RemovedRegisteredWorktrees  int64
	RemovedUnregisteredTempDirs int64
	RemovedWorkerDirs           int64
	ArchivedExecutionDirs       int64
	DeletedExecutionDirs        int64

	Warnings []agent.ExecutionCleanupWarning
}

type startupHousekeepingRunner struct {
	projectRoot     string
	tempRoot        string
	worktreeMaxAge  time.Duration
	workerDirMaxAge time.Duration
	now             func() time.Time
	retentionPolicy executionRetentionPolicy
}

func newStartupHousekeepingRunner(projectRoot string) *startupHousekeepingRunner {
	tempRoot := config.ExecutionWorktreeRoot(projectRoot)
	if tempRoot == "" {
		tempRoot = filepath.Join(os.TempDir(), agent.ExecuteBeadTmpSubdir)
	}
	return &startupHousekeepingRunner{
		projectRoot:     projectRoot,
		tempRoot:        tempRoot,
		worktreeMaxAge:  worktreeReapMaxAgeFromEnv(),
		workerDirMaxAge: defaultWorkerDirStaleAge,
		retentionPolicy: resolveExecutionRetentionPolicy(projectRoot),
	}
}

func (r *startupHousekeepingRunner) Cleanup(ctx context.Context) (agent.ExecutionCleanupSummary, error) {
	if r == nil {
		return agent.ExecutionCleanupSummary{}, nil
	}
	report, err := r.scan(ctx, true)
	if err != nil {
		return agent.ExecutionCleanupSummary{
			ProjectRoot: r.projectRoot,
			TempRoot:    r.tempRoot,
		}, err
	}
	return agent.ExecutionCleanupSummary{
		ProjectRoot:                 report.ProjectRoot,
		TempRoot:                    report.TempRoot,
		RemovedRegisteredWorktrees:  report.RemovedRegisteredWorktrees,
		RemovedUnregisteredTempDirs: report.RemovedUnregisteredTempDirs,
		RemovedWorkerDirs:           report.RemovedWorkerDirs,
		RemovedEvidenceDirs:         report.ArchivedExecutionDirs + report.DeletedExecutionDirs,
		Warnings:                    append([]agent.ExecutionCleanupWarning(nil), report.Warnings...),
	}, nil
}

func (r *startupHousekeepingRunner) scan(ctx context.Context, apply bool) (startupHousekeepingReport, error) {
	if r == nil {
		return startupHousekeepingReport{}, nil
	}
	report := startupHousekeepingReport{
		ProjectRoot: r.projectRoot,
		TempRoot:    r.tempRoot,
	}
	if r.projectRoot == "" {
		return report, nil
	}
	now := time.Now().UTC()
	if r.now != nil {
		now = r.now()
	}

	runStates, err := agent.ReadRunStates(r.projectRoot)
	if err != nil {
		return report, err
	}
	if err := r.scanWorktrees(ctx, now, runStates, apply, &report); err != nil {
		return report, err
	}
	if err := r.scanWorkerDirs(ctx, now, apply, &report); err != nil {
		return report, err
	}
	if err := r.scanExecutionDirs(ctx, now, runStates, apply, &report); err != nil {
		return report, err
	}
	return report, nil
}

func (r *startupHousekeepingRunner) scanWorktrees(ctx context.Context, now time.Time, runStates []agent.RunState, apply bool, report *startupHousekeepingReport) error {
	if report.TempRoot == "" {
		return nil
	}
	if ctx != nil {
		if err := ctx.Err(); err != nil {
			return err
		}
	}
	entries, err := os.ReadDir(report.TempRoot)
	if err != nil {
		if os.IsNotExist(err) {
			return nil
		}
		return err
	}

	registered := map[string]struct{}{}
	if paths, listErr := (&agent.RealGitOps{}).WorktreeList(r.projectRoot); listErr == nil {
		for _, path := range paths {
			registered[filepath.Clean(path)] = struct{}{}
		}
	}

	for _, entry := range entries {
		if !entry.IsDir() || !strings.HasPrefix(entry.Name(), agent.ExecuteBeadWtPrefix) {
			continue
		}
		if ctx != nil {
			if err := ctx.Err(); err != nil {
				return err
			}
		}
		info, err := entry.Info()
		if err != nil {
			report.Warnings = append(report.Warnings, agent.ExecutionCleanupWarning{
				Path:    filepath.Join(report.TempRoot, entry.Name()),
				Class:   "worktree_stat",
				Message: err.Error(),
			})
			continue
		}
		if now.Sub(info.ModTime()) < r.worktreeMaxAge {
			continue
		}

		path := filepath.Join(report.TempRoot, entry.Name())
		meta, metaErr := agent.ReadExecutionCleanupMetadata(path)
		if metaErr == nil {
			meta.WorktreePath = firstNonEmpty(meta.WorktreePath, path)
		} else {
			meta = agent.ExecutionCleanupMetadata{WorktreePath: path}
		}
		if worktreeStillLive(meta, runStates, now) {
			continue
		}

		report.StaleWorktrees++
		if !apply {
			continue
		}

		if _, ok := registered[filepath.Clean(path)]; ok {
			if err := (&agent.RealGitOps{}).WorktreeRemove(r.projectRoot, path); err != nil {
				report.Warnings = append(report.Warnings, agent.ExecutionCleanupWarning{
					Path:    path,
					Class:   "registered_worktree_remove",
					Message: err.Error(),
				})
				continue
			}
			report.RemovedRegisteredWorktrees++
			continue
		}

		if err := os.RemoveAll(path); err != nil {
			report.Warnings = append(report.Warnings, agent.ExecutionCleanupWarning{
				Path:    path,
				Class:   "unregistered_worktree_remove",
				Message: err.Error(),
			})
			continue
		}
		report.RemovedUnregisteredTempDirs++
	}

	return nil
}

func (r *startupHousekeepingRunner) scanWorkerDirs(ctx context.Context, now time.Time, apply bool, report *startupHousekeepingReport) error {
	root := ddxroot.JoinProject(r.projectRoot, "workers")
	entries, err := os.ReadDir(root)
	if err != nil {
		if os.IsNotExist(err) {
			return nil
		}
		return err
	}

	for _, entry := range entries {
		if !entry.IsDir() || !strings.HasPrefix(entry.Name(), "agent-loop-") {
			continue
		}
		if ctx != nil {
			if err := ctx.Err(); err != nil {
				return err
			}
		}

		rec, err := workerstatus.ReadLiveness(r.projectRoot, entry.Name())
		if err != nil {
			report.Warnings = append(report.Warnings, agent.ExecutionCleanupWarning{
				Path:    filepath.Join(root, entry.Name(), "status.json"),
				Class:   "worker_dir_read",
				Message: err.Error(),
			})
			continue
		}
		stale, _ := staleWorkerDir(rec, now, r.workerDirMaxAge)
		if !stale {
			continue
		}

		report.StaleWorkerDirs++
		if !apply {
			continue
		}

		dirPath := filepath.Join(root, entry.Name())
		if err := os.RemoveAll(dirPath); err != nil {
			report.Warnings = append(report.Warnings, agent.ExecutionCleanupWarning{
				Path:    dirPath,
				Class:   "worker_dir_remove",
				Message: err.Error(),
			})
			continue
		}
		report.RemovedWorkerDirs++
	}

	return nil
}

func (r *startupHousekeepingRunner) scanExecutionDirs(ctx context.Context, now time.Time, runStates []agent.RunState, apply bool, report *startupHousekeepingReport) error {
	policy := r.retentionPolicy
	if policy.mode == executionRetentionDisabled {
		return nil
	}

	root := ddxroot.JoinProject(r.projectRoot, "executions")
	entries, err := os.ReadDir(root)
	if err != nil {
		if os.IsNotExist(err) {
			return nil
		}
		return err
	}

	activeAttempts := map[string]struct{}{}
	for _, rs := range runStates {
		if rs.AttemptID != "" {
			activeAttempts[rs.AttemptID] = struct{}{}
		}
	}
	cutoff := now.AddDate(0, 0, -policy.days)

	for _, entry := range entries {
		if !entry.IsDir() {
			continue
		}
		if _, ok := activeAttempts[entry.Name()]; ok {
			continue
		}
		if ctx != nil {
			if err := ctx.Err(); err != nil {
				return err
			}
		}

		dirPath := filepath.Join(root, entry.Name())
		if !hasExecutionEvidenceMarker(dirPath) {
			continue
		}

		info, err := entry.Info()
		if err != nil {
			report.Warnings = append(report.Warnings, agent.ExecutionCleanupWarning{
				Path:    dirPath,

				"Inspect .ddx/workers, .ddx/executions, and the execution worktree root manually",
				"Run 'ddx doctor --apply' again after fixing the underlying filesystem issue",
			},
		}
		issues = append(issues, issue)
		fmt.Printf("   ⚠️  %s\n", issue.Description)
	} else {
		if applyHousekeeping {
			fmt.Printf("✅ stale worktrees=%d, stale worker dirs=%d, stale execution dirs=%d (applied)\n",
				housekeepingReport.StaleWorktrees,
				housekeepingReport.StaleWorkerDirs,
				housekeepingReport.StaleExecutionDirs,
			)
		} else if housekeepingReport.StaleWorktrees > 0 || housekeepingReport.StaleWorkerDirs > 0 || housekeepingReport.StaleExecutionDirs > 0 {
			fmt.Printf("⚠️  stale worktrees=%d, stale worker dirs=%d, stale execution dirs=%d\n",
				housekeepingReport.StaleWorktrees,
				housekeepingReport.StaleWorkerDirs,
				housekeepingReport.StaleExecutionDirs,
			)
			issues = append(issues, DiagnosticIssue{
				Type: "execution_housekeeping",
				Description: fmt.Sprintf("Stale execution state detected (%d worktrees, %d worker dirs, %d execution dirs)",
					housekeepingReport.StaleWorktrees,
					housekeepingReport.StaleWorkerDirs,
					housekeepingReport.StaleExecutionDirs,
				),
				Remediation: []string{
					"Run 'ddx doctor --apply' to reap stale worktrees, worker dirs, and execution evidence",
					"Adjust DDX_WORKTREE_REAP_MAX_AGE or DDX_EXECUTION_RETAIN_DAYS if the retention window is too aggressive",
				},
			})
		} else {
			fmt.Println("✅ No stale worktrees, worker dirs, or execution dirs")
		}
		for _, warning := range housekeepingReport.Warnings {
			fmt.Printf("   ⚠️  %s (%s): %s\n", warning.Path, warning.Class, warning.Message)
		}
	}

	// Check 13: package.json locations — detect missing/stale node_modules.
	fmt.Print("✓ Checking package.json locations... ")
	pkgIssues := checkPackageJSONLocations(f.WorkingDir)
	if len(pkgIssues) == 0 {
		fmt.Println("✅ Node dependencies up to date")
	} else {
		fmt.Printf("⚠️  %d location(s) need 'bun install'\n", len(pkgIssues))
		for _, issue := range pkgIssues {
			fmt.Printf("   ⚠️  %s\n", issue.Description)
			for _, r := range issue.Remediation {
				fmt.Printf("   💡 %s\n", r)
			}
		}
		issues = append(issues, pkgIssues...)
	}

	// Check 14: Legacy symlinks under project skill directories (FEAT-015).
	// In the project-local model all skills are real files. Symlinks indicate
	// a pre-migration install; ddx update --force replaces them.
	if legacyDirs := legacySkillSymlinkDirs(f.WorkingDir); len(legacyDirs) > 0 {
		errOut := cmd.ErrOrStderr()
		for _, dir := range legacyDirs {
			fmt.Fprintf(errOut, "symlink detected under %s; pre-migration install detected\n", dir)
		}
		fmt.Fprintln(errOut, "run: ddx update --force")
		return fmt.Errorf("legacy skill symlinks detected")
	}

	fmt.Println()
	if allGood && len(issues) == 0 {
		fmt.Println("🎉 All critical checks passed! DDX is ready to use.")
	} else if allGood && len(issues) > 0 {
		fmt.Println("⚠️  Some non-critical issues detected. DDX is functional but may have limitations.")
		fmt.Println("💡 Run 'ddx doctor --help' for troubleshooting tips.")
	} else {
		fmt.Println("⚠️  Some issues detected. DDX may have limited functionality.")
		fmt.Println("💡 Run 'ddx doctor --help' for troubleshooting tips.")
	}

	// Generate detailed diagnostic report if verbose or issues detected
	if verbose || len(issues) > 0 {
		generateDiagnosticReport(issues, verbose, f.WorkingDir)
	}

	return nil
}

// legacySkillSymlinkDirs returns the relative names of skill directories
// (e.g. ".agents/skills", ".claude/skills") under workingDir that contain
// at least one symlink. A symlink indicates a pre-FEAT-015 install.
func legacySkillSymlinkDirs(workingDir string) []string {
	if workingDir == "" {
		return nil
	}
	var found []string
	for _, rel := range []string{".agents/skills", ".claude/skills"} {
		dir := filepath.Join(workingDir, rel)
		entries, err := os.ReadDir(dir)
		if err != nil {
			continue
		}
		for _, e := range entries {
			info, err := e.Info()
			if err != nil {
				continue
			}
			if info.Mode()&os.ModeSymlink != 0 {
				found = append(found, rel)
				break
			}
		}
	}
	return found
}

// runDoctorScoped runs only the checks relevant to the staged file paths,
// skipping global installation health checks unrelated to those files.
// It is the entry point when the ddx-validate pre-commit hook passes --paths.
//
// Scope rules:
//   - path == ".ddx.yml" (or ends with "/.ddx.yml") → config category: run config validation
//   - path under templates/, patterns/, prompts/ → resource category: validate resource files
//
// Any other paths (e.g. Go source files staged alongside config) are silently
// ignored — the scoped run only validates the DDx-relevant categories present
// in the staged set. Global checks (legacy symlinks, binary location, git repo
// health, etc.) are never run in scoped mode.
func (f *CommandFactory) runDoctorScoped(paths []string) error {
	cats := categorizeStagedPaths(paths)
	if cats["config"] {
		if !checkConfiguration() {
			return fmt.Errorf("DDx configuration invalid; run 'ddx doctor' for details")
		}
	}
	// Resource category: syntax/schema checks for templates, patterns, prompts.
	// Currently no additional validation beyond categorisation; the hook gate
	// is satisfied by a clean parse (no-op until resource validators are added).
	_ = cats["resource"]
	return nil
}

// categorizeStagedPaths maps each path to a DDx check category.
// Returns a set of category names ("config", "resource") that apply to the
// given path list. Unrecognised paths produce no category.
func categorizeStagedPaths(paths []string) map[string]bool {
	cats := make(map[string]bool)
	resourcePrefixes := []string{"templates/", "patterns/", "prompts/"}
	for _, p := range paths {
		p = strings.TrimSpace(p)
		if p == "" {
			continue
		}
		if p == ".ddx.yml" || strings.HasSuffix(p, "/.ddx.yml") || filepath.Base(p) == ".ddx.yml" {
			cats["config"] = true
		}
		for _, prefix := range resourcePrefixes {
			if strings.HasPrefix(p, prefix) || strings.Contains(p, "/"+prefix) {
				cats["resource"] = true
			}
		}
	}
	return cats
}

// checkBinaryInstallLocation verifies the running binary is at the canonical install
// location ($HOME/.local/bin/ddx) and scans PATH for other ddx copies whose
// SHA-256 differs from the running binary.
func checkBinaryInstallLocation(executable string) []DiagnosticIssue {
	var issues []DiagnosticIssue

	homeDir, err := os.UserHomeDir()
	if err != nil {
		return issues
	}

	canonicalPath := filepath.Join(homeDir, ".local", "bin", "ddx")

	// (2) Check whether running binary matches the canonical install location.
	resolvedExec, _ := filepath.EvalSymlinks(executable)
	if resolvedExec == "" {
		resolvedExec = executable
	}
	resolvedCanonical, _ := filepath.EvalSymlinks(canonicalPath)
	execMatchesCanonical := resolvedExec == canonicalPath ||
		(resolvedCanonical != "" && resolvedExec == resolvedCanonical)
	if !execMatchesCanonical {
		issues = append(issues, DiagnosticIssue{
			Type:        "binary_not_canonical",
			Description: fmt.Sprintf("Running binary (%s) is not at canonical install location (%s)", executable, canonicalPath),
			Remediation: []string{
				"Re-run install.sh to reinstall to the canonical location",
				fmt.Sprintf("Or ensure %s is earlier in your PATH", filepath.Dir(canonicalPath)),
			},
		})
	}

	// (3) Walk PATH and flag any ddx copy whose SHA-256 differs from the running binary.
	runningSHA, err := computeFileSHA256(executable)
	if err != nil {
		return issues
	}

	return meta.WorktreePath != "" &&
		state.WorktreePath != "" &&
		filepath.Clean(state.WorktreePath) == filepath.Clean(meta.WorktreePath)
}

func processAlive(pid int) bool {
	if pid <= 0 {
		return false
	}
	proc, err := os.FindProcess(pid)
	if err != nil {
		return false
	}
	return proc.Signal(syscall.Signal(0)) == nil
}

func firstNonEmpty(values ...string) string {
	for _, value := range values {
		if strings.TrimSpace(value) != "" {
			return value
		}
	}
	return ""
}

func worktreeReapMaxAgeFromEnv() time.Duration {
	raw := strings.TrimSpace(os.Getenv("DDX_WORKTREE_REAP_MAX_AGE"))
	if raw == "" {
		return defaultWorktreeReapMaxAge
	}
	d, err := time.ParseDuration(raw)
	if err != nil || d <= 0 {
		return defaultWorktreeReapMaxAge
	}
	return d
}

// projectHasRoutingConfig reports whether the project's .ddx/config.yaml pins a
// routing decision that should suppress DDx's zero-config powerClass inference.
// agent.endpoints alone is transport configuration (where providers live) and
// does NOT pin routing — leaving it on the suppression list caused no-flag work
// in projects with local endpoints to send an empty Policy and inherit
// Fizeau's default policy (which, with no DDx-supplied hint, scored Opus on
// ordinary implementation work; see ddx-e0b95b4a).
func projectHasRoutingConfig(projectRoot string) bool {
	if projectRoot == "" {
		return false
	}
	cfgPath := ddxroot.JoinProject(projectRoot, "config.yaml")
	if _, err := os.Stat(cfgPath); err != nil {
		return false
	}
	cfg, err := config.LoadWithWorkingDir(projectRoot)
	if err != nil || cfg == nil || cfg.Agent == nil {
		return false
	}
	a := cfg.Agent
	return strings.TrimSpace(a.Model) != ""
